// // This module translates a 16-bit virtual address to a 10-bit physical page number and a 6-bit offset. The physical page number is derived from the lower 10 bits of the virtual address, and the offset is from the upper 6 bits.
module virtual_memory_translation (
    input [15:0] virtual_address,
    output [9:0] physical_page_number,
    output [5:0] offset
);
    assign physical_page_number = virtual_address[15:6]; // Upper 10 bits
    assign offset = virtual_address[5:0]; // Lower 6 bits
endmodule
